  ('dietitian-moex-08639', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關基礎代謝率（BMR）的敘述，何者正確？', '["體溫升高1℃則BMR升高12-13%", "睡覺時的熱量消耗比BMR少15%", "成年人的BMR每10年約降低0.5%", "BMR升至比平常高一倍時，會使心跳加快，細胞質組織分解耗損增加"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
